#!/usr/bin/env node
/**
 * Scans assets/profiles/ for images and regenerates
 * src/data/profileImages.js with require() mappings.
 *
 * Usage: node scripts/sync-profile-images.js
 *
 * Run this after adding/removing images from assets/profiles/.
 * The generated file is committed to source control so the
 * Metro bundler knows which assets to bundle.
 */

const fs = require('fs');
const path = require('path');

const ROOT = path.resolve(__dirname, '..');
const PROFILES_DIR = path.join(ROOT, 'assets', 'profiles');
const OUTPUT_FILE = path.join(ROOT, 'src', 'data', 'profileImages.js');
const IMAGE_EXTENSIONS = ['.png', '.jpg', '.jpeg', '.webp'];

// 1. Scan for available images
const images = {};

if (fs.existsSync(PROFILES_DIR)) {
  for (const file of fs.readdirSync(PROFILES_DIR).sort()) {
    const ext = path.extname(file).toLowerCase();
    if (IMAGE_EXTENSIONS.includes(ext)) {
      const id = path.basename(file, ext);
      images[id] = file;
    }
  }
}

const count = Object.keys(images).length;
console.log(`Found ${count} profile image(s) in assets/profiles/`);

if (count === 0) {
  console.log('No images found. Add images named {profile-id}.png to assets/profiles/ first.');
}

// 2. Generate the mapping file
const requireLines = Object.entries(images)
  .map(([id, file]) => `  "${id}": require("../../assets/profiles/${file}"),`)
  .join('\n');

const output = `// Profile Image Registry \u2014 AUTO-GENERATED
// DO NOT EDIT \u2014 regenerated by: node scripts/sync-profile-images.js
// Generated: ${new Date().toISOString()}
//
// Demo/dev: images bundled from assets/profiles/{id}.png
// Production: profiles have remote URLs in photo field (takes priority)

export const PROFILE_IMAGES = {
${requireLines || '  // No images yet. Add to assets/profiles/ and re-run this script.'}
};
`;

fs.writeFileSync(OUTPUT_FILE, output, 'utf-8');
console.log(`Written to src/data/profileImages.js (${count} entries)`);

// 3. Report coverage
try {
  const dataFile = fs.readFileSync(path.join(ROOT, 'src', 'data', 'discoverProfiles.js'), 'utf-8');
  const allIds = [...dataFile.matchAll(/"id":\s*"([^"]+)"/g)].map(m => m[1]);
  const covered = allIds.filter(id => images[id]);
  const missing = allIds.filter(id => !images[id]);
  console.log(`\nCoverage: ${covered.length}/${allIds.length} profiles have images`);
  if (missing.length > 0 && missing.length <= 30) {
    console.log('\nMissing images:');
    missing.forEach(id => console.log(`  - ${id}`));
  } else if (missing.length > 30) {
    console.log(`${missing.length} profiles still need images. Use --list-missing to see all.`);
    if (process.argv.includes('--list-missing')) {
      missing.forEach(id => console.log(`  - ${id}`));
    }
  }
} catch (e) {
  // discoverProfiles.js not readable as plain text
}
